+#ifdef JSON_HAS_CPP_17
+namespace variant_detail
+{
+template<std::size_t I, typename BasicJsonType, typename... Types>
+void from_json_variant_alt(const BasicJsonType& j, std::variant<Types...>& v, std::size_t idx)
+{
+    if (I == idx)
+    {
+        v = j.template get<std::variant_alternative_t<I, std::variant<Types...>>>();
+    }
+}
+
+template<typename BasicJsonType, typename... Types, std::size_t... Is>
+void from_json_variant_impl(const BasicJsonType& j, std::variant<Types...>& v,
+                            std::size_t idx, index_sequence<Is...> /*unused*/)
+{
+    (from_json_variant_alt<Is>(j, v, idx), ...);
+}
+} // namespace variant_detail
+
+template<typename BasicJsonType, typename... Types,
+         enable_if_t<is_variant<std::variant<Types...>>::value, int> = 0>
+void from_json(const BasicJsonType& j, std::variant<Types...>& v)
+{
+    const auto idx = j.at(0).template get<std::size_t>();
+    variant_detail::from_json_variant_impl(j.at(1), v, idx, index_sequence_for<Types...> {});
+}
+#endif
+
