 #endif

 #include <algorithm> // copy
@@ -459,6 +460,19 @@ inline void to_json(BasicJsonType& j, const std_fs::path& p)
 }
 #endif

+#ifdef JSON_HAS_CPP_17
+template<typename BasicJsonType, typename... Types,
+         enable_if_t<is_variant<std::variant<Types...>>::value, int> = 0>
+void to_json(BasicJsonType& j, const std::variant<Types...>& v)
+{
+    j = {v.index(),
+         std::visit([](const auto& alt) -> BasicJsonType
+    {
+        return alt;
+    }, v)};
+}
+#endif
